	// set bit 3 to 1
	//*ptr_rcc = *ptr_rcc | (1 << 3);

	// set port D to be 1
	ptr_rcc->GPIOD = 1;

	// 2. Set port D pin 15 to be output
	GPIO_PORT_MODE* ptr_mode = (GPIO_PORT_MODE*)(GPIOD_ADDR + GPIOx_MODER_OFFSET);

	//set bit 30 to 1
