	// set bit 31 to 0
	//*ptr_mode = *ptr_mode & ~(1 << 31);

	ptr_mode->MODER15 = 1;	// 01 = output

	//Blink PD15
	// Create a pointer to point to GPIO_D pin 15
	GPIO_PORT_OUTPUT* ptr_out_d = (GPIO_PORT_OUTPUT*)(GPIOD_ADDR + GPIOx_ADDR_OFFSET);

	// 2. Push button (PA0) - port mode - input
